async function streamTTS(text: string, voiceProfile: string): Promise<void> {
  const apiKey = 'your_api_key';
  const endpoint = 'https://api.qwen.ai/v1/tts/customvoice/stream';

  const response = await fetch(endpoint, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      text,
      voice_profile: voiceProfile,
      output_format: 'wav',
      stream: true
    })
  });

  if (!response.ok) {
    throw new Error(`API error: ${response.status}`);
  }

  const audioContext = new AudioContext();
  const reader = response.body!.getReader();
  const chunks: Uint8Array[] = [];

  while (true) {
    const { done, value } = await reader.read();
    if (done) break;
    chunks.push(value);
    // Play chunk immediately for streaming
    const audioBuffer = await audioContext.decodeAudioData(value.buffer);
    const source = audioContext.createBufferSource();
    source.buffer = audioBuffer;
    source.connect(audioContext.destination);
    source.start();
  }
}
